class TreeNode { public:
    int val;
    TreeNode *left;
    TreeNode *right;

    TreeNode(int x) : val(x), left(NULL), right(NULL) {}

    vector<int> calcDepth(vector<TreeNode*> nodes);

};

class Solution {
public:
    vector<int> solve(vector<TreeNode*> nodes) {
        if (!nodes.size()) return vector<int>();

        vector<bool> visited(nodes.size(), false);
        vector<int> result;

        queue<pair<TreeNode*, int>> q;
        q.push(make_pair(nodes[0], 0));

        while (!q.empty()) {
            auto [node, depth] = q.front();
            q.pop();

            if (node) {
                result.push_back(depth);
                q.push(make_pair(node->left, depth + 1));
                q.push(make_pair(node->right, depth + 1));
            }

        }
        return result;
    }
};

int main() {
    Solution solution;
    TreeNode root(1);
    root.left = new TreeNode(2);
    root.right = new TreeNode(3);
    root.left->left = new TreeNode(4);
    root.left->right = new TreeNode(5);

    auto result = solution.solve({&root});
    for (auto depth : result) {
        std::cout << depth << ' ';
    }
    return 0;
}
